"use server";

import { db } from "@/db";
import { estimates, estimateItems } from "@/db/schema";
import { eq } from "drizzle-orm";
import { redirect } from "next/navigation";
import { revalidatePath } from "next/cache";

export type EstimateItemInput = {
  section: "robocizna" | "materialy";
  name: string;
  unit: string;
  quantity: number;
  unitPrice: number;
};

export type CreateEstimateInput = {
  clientName: string;
  clientAddress?: string;
  clientNip?: string;
  city?: string;
  date: string;
  currency: "PLN" | "EUR";
  vatRate: number;
  validUntil?: string;
  notes?: string;
  items: EstimateItemInput[];
};

export async function createEstimate(data: CreateEstimateInput) {
  const [estimate] = await db
    .insert(estimates)
    .values({
      clientName: data.clientName,
      clientAddress: data.clientAddress || null,
      clientNip: data.clientNip || null,
      city: data.city || "Kraków",
      date: data.date,
      currency: data.currency,
      vatRate: data.vatRate.toFixed(2),
      validUntil: data.validUntil || null,
      notes: data.notes || null,
    })
    .returning();

  if (data.items.length > 0) {
    await db.insert(estimateItems).values(
      data.items.map((item, idx) => ({
        estimateId: estimate.id,
        section: item.section,
        name: item.name,
        unit: item.unit,
        quantity: item.quantity.toFixed(2),
        unitPrice: item.unitPrice.toFixed(2),
        sortOrder: idx,
      }))
    );
  }

  revalidatePath("/kosztorysy");
  redirect(`/kosztorysy/${estimate.id}`);
}

export async function deleteEstimate(id: number) {
  await db.delete(estimates).where(eq(estimates.id, id));
  revalidatePath("/kosztorysy");
  redirect("/kosztorysy");
}

import { db } from "@/db";
import { estimates, estimateItems } from "@/db/schema";
import { desc, sql } from "drizzle-orm";
import Link from "next/link";
import { formatMoney, toNumber } from "@/lib/format";

export const dynamic = "force-dynamic";

export default async function KosztorysyPage() {
  const list = await db.select().from(estimates).orderBy(desc(estimates.createdAt));

  const totals = await db
    .select({
      estimateId: estimateItems.estimateId,
      total: sql<string>`sum(${estimateItems.quantity} * ${estimateItems.unitPrice})`,
    })
    .from(estimateItems)
    .groupBy(estimateItems.estimateId);

  const totalsMap = new Map(totals.map((t) => [t.estimateId, toNumber(t.total)]));

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-semibold text-neutral-900">Кошториси</h1>
        <Link
          href="/kosztorysy/new"
          className="bg-neutral-900 hover:bg-neutral-800 text-white rounded-lg px-4 py-2 text-sm font-medium transition"
        >
          + Новий кошторис
        </Link>
      </div>

      {list.length === 0 ? (
        <p className="text-sm text-neutral-400">Кошторисів ще немає. Створи перший.</p>
      ) : (
        <div className="bg-white border border-neutral-200 rounded-xl overflow-hidden">
          <table className="w-full text-sm">
            <thead>
              <tr className="text-left text-neutral-500 text-xs border-b border-neutral-100">
                <th className="py-2 px-3 font-medium">Клієнт</th>
                <th className="py-2 px-3 font-medium">Дата</th>
                <th className="py-2 px-3 font-medium">Сума (брутто)</th>
                <th className="py-2 px-3 font-medium"></th>
              </tr>
            </thead>
            <tbody>
              {list.map((e) => {
                const netto = totalsMap.get(e.id) ?? 0;
                const vat = netto * (toNumber(e.vatRate) / 100);
                return (
                  <tr key={e.id} className="border-t border-neutral-100 hover:bg-neutral-50">
                    <td className="py-2 px-3">{e.clientName}</td>
                    <td className="py-2 px-3 text-neutral-500">{e.date}</td>
                    <td className="py-2 px-3">
                      {formatMoney(netto + vat, e.currency as "PLN" | "EUR")}
                    </td>
                    <td className="py-2 px-3 text-right">
                      <Link href={`/kosztorysy/${e.id}`} className="text-neutral-600 hover:text-neutral-900">
                        Відкрити →
                      </Link>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

"use client";

import { useMemo, useState } from "react";
import type { PriceItem } from "@/db/schema";

export default function AutocompleteInput({
  value,
  options,
  onChange,
  onSelect,
  placeholder,
}: {
  value: string;
  options: PriceItem[];
  onChange: (value: string) => void;
  onSelect: (item: PriceItem) => void;
  placeholder?: string;
}) {
  const [focused, setFocused] = useState(false);

  const matches = useMemo(() => {
    const q = value.trim().toLowerCase();
    if (!q) return options.slice(0, 8);
    return options.filter((o) => o.name.toLowerCase().includes(q)).slice(0, 8);
  }, [value, options]);

  return (
    <div className="relative">
      <input
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onFocus={() => setFocused(true)}
        onBlur={() => setTimeout(() => setFocused(false), 150)}
        placeholder={placeholder ?? "Назва позиції..."}
        className="w-full border rounded px-2 py-1.5 text-sm"
      />
      {focused && matches.length > 0 && (
        <div className="absolute z-10 mt-1 w-full max-h-56 overflow-auto bg-white border border-neutral-200 rounded-lg shadow-lg text-sm">
          {matches.map((m) => (
            <button
              type="button"
              key={m.id}
              onMouseDown={(e) => {
                e.preventDefault();
                onSelect(m);
                setFocused(false);
              }}
              className="w-full text-left px-3 py-2 hover:bg-neutral-50 flex items-center justify-between gap-2"
            >
              <span className="truncate">{m.name}</span>
              <span className="text-neutral-400 whitespace-nowrap text-xs">
                {m.priceMin}
                {m.priceMax ? `–${m.priceMax}` : ""} {m.currency}/{m.unit}
              </span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

